import { useMouseMove, animate, useValue } from "react-ui-animate"

import Guppy from "./svg/Guppy.js"

function GuppyCursor({page}) {
    // var [x, setX] = useState(0)
    // var [y, setY] = useState(0)
    const x = useValue(0)
    const y = useValue(0)
    const angle = useValue(0)
    const xAcc = useValue(0)
    const yAcc = useValue(0)
    const maxAcc = 10

    useMouseMove(({mouseX, mouseY}) => {
        var deltaX = mouseX - x.value.value;
        var deltaY = mouseY - y.value.value;

        var flipVal = 0
        if (deltaX < 0) {
          flipVal = 180
        }
        angle.value = Math.atan(deltaY/deltaX) * 180/Math.PI

        var pr = Math.atan(deltaY/deltaX) * 180/Math.PI
        console.log(deltaX," | ", deltaY)

        xAcc.value = (deltaX / 500) * maxAcc + 1
        yAcc.value = (deltaY / 500) * maxAcc + 1

        x.value = x.value.value + xAcc.value.value;
        y.value = y.value.value + yAcc.value.value;
    });


  return (
    <animate.div
    style={{
        width: "10em",
        aspectRatio: "1261/652",
        border: "red 2px solid",
        position: "fixed",
        top: 0,
        left: 0,
        translateX: x.value,
        translateY: y.value,
        rotate: angle.value,
    }}
  >

    <Guppy />

  </animate.div>


  )
}

export default GuppyCursor;
